import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router, RouterModule } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [
    CommonModule,
    ReactiveFormsModule,
    RouterModule
  ],
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.css']
})
export class LoginComponent {
  private fb = inject(FormBuilder);
  private authService = inject(AuthService);
  private router = inject(Router);

  loginForm: FormGroup = this.fb.group({
    correo: ['', [Validators.required, Validators.email]],
    password: ['', [Validators.required, Validators.minLength(6)]],
    rememberMe: [false]
  });

  hidePassword = true;
  isLoading = false;
  errorMessage = '';

  onSubmit(): void {
    if (this.loginForm.invalid) {
      return;
    }

    this.isLoading = true;
    this.errorMessage = '';

    const { correo, password } = this.loginForm.value;

    this.authService.login({ correo, password }).subscribe({
      next: (response: any) => {
        this.isLoading = false;
        // Redirigir al dashboard tras inicio de sesión exitoso
        this.router.navigate(['/dashboard']);
      },
      error: (err: any) => {
        this.isLoading = false;
        this.errorMessage = err.error?.message || 'Error al conectar con el servidor. Verifique sus credenciales.';
      }
    });
  }
}
<main class="flex-grow flex flex-col md:flex-row w-full h-full">
  <!-- Left Side: Image with Clean Structured Split (No Wave Clip) -->
  <div class="hidden md:block md:w-1/2 relative bg-surface-container h-full overflow-hidden border-r border-outline-variant/30">
    <div class="absolute inset-0 bg-primary/20 z-10 mix-blend-multiply"></div>
    <img alt="Students studying in a modern campus environment" class="absolute inset-0 w-full h-full object-cover z-0" src="https://lh3.googleusercontent.com/aida-public/AB6AXuCvO_ASC5Fw7o9N9eo0jk_Ss7x7zjI0T1d3KjesjkhKKYAs3bdB191dgAaqGvw2HriAtxNk2sxIGuZMid4FhegrG5QCy6IF42UhCmt6LP_qnzp-r8K4hj52o3ALPrA-d-r3A_CfjLISxHTGkQNgR2SrvFK2ueLiDHpX09EyfZu0dwmLb5_v1eGHqfPrtT4QjYe7wBrm6qVb1WrqyGWozTPGj4DDSD_a2oZ4yHpBK9dyta261jvPI-R4BajEHirB3EndNcDnME5EPow">
    <div class="absolute inset-0 bg-gradient-to-t from-black/70 via-black/30 to-transparent z-10"></div>
    <div class="absolute bottom-16 left-16 z-20 text-white max-w-md">
      <h2 class="font-headline text-4xl font-bold mb-4 leading-tight">Innovación Fluida en el Aprendizaje.</h2>
      <p class="font-body text-base opacity-95 leading-relaxed">Accede a una experiencia educativa sin fronteras. Conecta, colabora y descubre nuevas posibilidades.</p>
    </div>
  </div>

  <!-- Right Side: Structured Login Form -->
  <div class="w-full md:w-1/2 flex items-center justify-center p-12 bg-surface-container-low relative h-full">
    <!-- Clean, subtle background decor -->
    <div class="absolute top-10 right-10 w-80 h-80 bg-primary-fixed/10 rounded-full blur-3xl pointer-events-none"></div>
    <div class="absolute bottom-10 left-10 w-60 h-60 bg-tertiary-fixed/10 rounded-full blur-3xl pointer-events-none"></div>

    <!-- Login Box: More squared (rounded-md), structured, and balanced -->
    <div class="w-full max-w-md bg-surface-container-lowest p-10 rounded-md border border-outline-variant/40 deep-shadow relative z-10 transition-transform duration-300">

      <!-- Top header -->
      <div class="mb-10 text-center">
        <div class="inline-flex items-center justify-center w-14 h-14 rounded-md bg-primary/10 text-primary mb-4 border border-primary/20">
          <span class="material-symbols-outlined text-3xl" style="font-variation-settings: 'FILL' 1;">school</span>
        </div>
        <h1 class="font-headline text-2xl font-bold text-on-surface tracking-tight">Campus Virtual INSTEIP</h1>
        <p class="font-body text-on-surface-variant mt-2 text-xs uppercase tracking-wider font-semibold">Credenciales de Acceso</p>
      </div>

      <form [formGroup]="loginForm" (ngSubmit)="onSubmit()" class="space-y-6">
        <!-- Error alert message -->
        @if (errorMessage) {
          <div class="flex items-center gap-3 bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-md text-xs font-medium">
            <span class="material-symbols-outlined text-base">error_outline</span>
            <span>{{ errorMessage }}</span>
          </div>
        }

        <!-- Username Input: Squared (rounded-md) -->
        <div>
          <label class="block font-label text-xs font-bold text-on-surface-variant mb-2 uppercase tracking-wider" for="email">Nombre de Usuario</label>
          <div class="relative">
            <div class="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
              <span class="material-symbols-outlined text-outline text-lg">person</span>
            </div>
            <input 
              formControlName="correo" 
              class="block w-full pl-10 pr-3 py-3 border border-outline rounded-md bg-surface-container-lowest text-on-surface focus:ring-1 focus:ring-primary focus:border-primary transition-all duration-200 placeholder-outline text-sm" 
              id="email" 
              placeholder="ejemplo@insteip.com" 
              type="email">
          </div>
          @if (loginForm.get('correo')?.hasError('required') && loginForm.get('correo')?.touched) {
            <p class="text-xs text-red-600 mt-1.5 flex items-center gap-1"><span class="material-symbols-outlined text-xs">info</span> El usuario es obligatorio.</p>
          }
          @if (loginForm.get('correo')?.hasError('email') && loginForm.get('correo')?.touched) {
            <p class="text-xs text-red-600 mt-1.5 flex items-center gap-1"><span class="material-symbols-outlined text-xs">info</span> Ingrese un correo válido.</p>
          }
        </div>

        <!-- Password Input: Squared (rounded-md) -->
        <div>
          <div class="flex items-center justify-between mb-2">
            <label class="block font-label text-xs font-bold text-on-surface-variant uppercase tracking-wider" for="password">Contraseña</label>
            <a class="font-body text-xs text-primary hover:text-primary-container font-semibold transition-colors" href="#">¿Olvidaste tu contraseña?</a>
          </div>
          <div class="relative">
            <div class="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
              <span class="material-symbols-outlined text-outline text-lg">lock</span>
            </div>
            <input 
              formControlName="password" 
              [type]="hidePassword ? 'password' : 'text'" 
              class="block w-full pl-10 pr-10 py-3 border border-outline rounded-md bg-surface-container-lowest text-on-surface focus:ring-1 focus:ring-primary focus:border-primary transition-all duration-200 text-sm" 
              id="password" 
              placeholder="••••••••">
            <div 
              (click)="hidePassword = !hidePassword"
              class="absolute inset-y-0 right-0 pr-3.5 flex items-center cursor-pointer text-outline hover:text-on-surface transition-colors">
              <span class="material-symbols-outlined text-base">
                {{ hidePassword ? 'visibility' : 'visibility_off' }}
              </span>
            </div>
          </div>
          @if (loginForm.get('password')?.hasError('required') && loginForm.get('password')?.touched) {
            <p class="text-xs text-red-600 mt-1.5 flex items-center gap-1"><span class="material-symbols-outlined text-xs">info</span> La contraseña es obligatoria.</p>
          }
        </div>

        <!-- Remember Me Checkbox -->
        <div class="flex items-center">
          <input 
            formControlName="rememberMe" 
            class="h-4 w-4 text-primary focus:ring-primary border-outline rounded-md bg-surface-container-lowest" 
            id="remember-me" 
            name="remember-me" 
            type="checkbox">
          <label class="ml-2 block text-xs font-body text-on-surface-variant font-medium" for="remember-me">
            Mantener sesión iniciada
          </label>
        </div>

        <!-- Submit Button: Squared with clean border radius -->
        <button 
          [disabled]="loginForm.invalid || isLoading" 
          class="w-full flex justify-center py-3 px-4 border border-transparent rounded-md text-xs font-label font-bold text-on-primary gradient-btn focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary transition-all duration-300 uppercase tracking-widest shadow-sm disabled:opacity-50 disabled:cursor-not-allowed" 
          type="submit">
          @if (isLoading) {
            Procesando...
          } @else {
            Iniciar Sesión
          }
        </button>
      </form>

      <!-- IT Support Section -->
      <div class="mt-8 text-center border-t border-surface-variant pt-6">
        <p class="font-body text-xs text-on-surface-variant">
          ¿Problemas para acceder? <a class="text-primary hover:underline font-semibold" href="#">Contactar Soporte IT</a>
        </p>
      </div>
    </div>

    <!-- Footer integrated -->
    <footer class="absolute bottom-0 left-0 w-full bg-transparent">
      <div class="flex flex-col md:flex-row justify-between items-center px-12 py-6 w-full">
        <div class="font-label font-bold text-on-surface text-xs mb-2 md:mb-0">© 2024 Instituto INSTEIP. Todos los derechos reservados.</div>
        <div class="flex gap-6">
          <a class="font-body text-xs text-on-surface-variant hover:text-primary transition-colors" href="#">Privacidad</a>
          <a class="font-body text-xs text-on-surface-variant hover:text-primary transition-colors" href="#">Términos de Uso</a>
          <a class="font-body text-xs text-on-surface-variant hover:text-primary transition-colors" href="#">Contacto</a>
        </div>
      </div>
    </footer>
  </div>
</main>
